import React, { useState, useEffect, useCallback, useRef } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

export default function AnswerPage() {
  const navigate = useNavigate();

  // User state from localStorage for authentication and subscription checks
  const [user, setUser] = useState(null);
  const [isUserPaid, setIsUserPaid] = useState(false);

  // Exam flow states
  const [currentPhase, setCurrentPhase] = useState('categorySelection'); // 'categorySelection', 'examInProgress', 'examSubmitted', 'viewAnswers'

  // Data selection states
  const [categories, setCategories] = useState([]); // This will hold structured data from backend
  const [sections, setSections] = useState([]); // Sections of the currently selected category
  const [sets, setSets] = useState([]); // Sets of the currently selected section

  const [selectedCategory, setSelectedCategory] = useState('');
  const [selectedSection, setSelectedSection] = useState('');
  const [selectedSet, setSelectedSet] = useState(''); // Stores the selected set's name
  const [selectedSetTimeLimit, setSelectedSetTimeLimit] = useState(0); // Time limit for the selected set

  // Exam specific states
  const [questions, setQuestions] = useState([]); // Questions for the current exam
  const [userAnswers, setUserAnswers] = useState({}); // Stores { questionId: 'selectedOptionLetter' } - THIS LINE IS CRUCIAL
  const [timeLeft, setTimeLeft] = useState(0); // Time left in seconds
  const timerIntervalRef = useRef(null); // Ref to hold the timer interval ID

  // Post-exam states
  const [examResult, setExamResult] = useState(null); // Summary after submission
  const [examDetailsForReview, setExamDetailsForReview] = useState(null); // Detailed review data

  // Loading and error states
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  // --- Initial Load & User Check ---
  useEffect(() => {
    const storedUser = JSON.parse(localStorage.getItem('user'));
    if (!storedUser) {
      alert('Please sign in to access the exam page.');
      navigate('/user-signin'); // Redirect to user sign-in if no user
    } else {
      setUser(storedUser);
      // REFINED SUBSCRIPTION CHECK:
      const now = new Date();
      const hasActivePaidSubscription = storedUser.subscriptions && storedUser.subscriptions.some(sub =>
        sub.status === 'active' &&
        new Date(sub.startDate) <= now &&
        new Date(sub.endDate) >= now &&
        sub.planName !== 'Free' // Assuming 'Free' is not considered a paid plan
      );
      setIsUserPaid(hasActivePaidSubscription);

      // Fetch categories once user is loaded
      fetchCategories();
    }
  }, [navigate]);

  // --- Helper for Access Control Logic ---
  // Determines if a given section is accessible to a FREE user based on the specified rules.
  const isSectionAccessibleForFreeUser = useCallback((categoryName, sectionName) => {
    switch (categoryName) {
      case 'Beginner':
        return sectionName === 'Beginner';
      case 'Intermediate':
        return sectionName === 'Beginner Challenge';
      case 'Advanced':
        return sectionName === 'Beginner Level';
      default:
        return false; // Unknown categories default to not accessible for free users
    }
  }, []);

  // --- Fetching Categories, Sections, Sets ---
  const fetchCategories = async () => {
    setLoading(true);
    try {
      const res = await axios.get('http://localhost:3000/api/question-papers');
      setCategories(res.data);
    } catch (err) {
      console.error('Error fetching categories:', err);
      setError('Failed to load categories. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const fetchSections = useCallback(async (categoryName) => {
    setLoading(true);
    try {
      const res = await axios.get(`http://localhost:3000/api/categories/${categoryName}/sections`);
      setSections(res.data);
      // Reset selected section and set when category changes
      setSelectedSection('');
      setSelectedSet('');
      setSelectedSetTimeLimit(0);
    } catch (err) {
      console.error('Error fetching sections:', err);
      setError('Failed to load sections. Please try again.');
      setSections([]);
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchSets = useCallback(async (categoryName, sectionName) => {
    setLoading(true);
    try {
      const res = await axios.get(`http://localhost:3000/api/categories/${categoryName}/sections/${sectionName}/sets`);
      setSets(res.data);
      // Reset selected set when section changes
      setSelectedSet('');
      setSelectedSetTimeLimit(0);
    } catch (err) {
      console.error('Error fetching sets:', err);
      setError('Failed to load sets. Please try again.');
      setSets([]);
    } finally {
      setLoading(false);
    }
  }, []);

  // Use effects for fetching based on selection
  useEffect(() => {
    if (selectedCategory) {
      fetchSections(selectedCategory);
    }
  }, [selectedCategory, fetchSections]);

  useEffect(() => {
    if (selectedCategory && selectedSection) {
      fetchSets(selectedCategory, selectedSection);
    }
  }, [selectedCategory, selectedSection, fetchSets]);

  // --- Exam Logic ---

  const startExam = async () => {
    if (!selectedCategory || !selectedSection || !selectedSet) {
      alert('Please select a Category, Section, and Set to start the exam.');
      return;
    }

    // Double-check access rights before starting exam
    const selectedCategoryObj = categories.find(cat => cat.category === selectedCategory);
    const selectedSectionObj = selectedCategoryObj?.sections.find(sec => sec.name === selectedSection);

    if (selectedSectionObj && !isUserPaid && !isSectionAccessibleForFreeUser(selectedCategory, selectedSection)) {
      alert('This section is only available for Paid subscribers. Please upgrade your plan or choose a free section.');
      return;
    }

    setLoading(true);
    setError(null);
    try {
      const questionsRes = await axios.get(`http://localhost:3000/api/questions/${selectedCategory}/${selectedSection}/${selectedSet}`);
      setQuestions(questionsRes.data);

      const currentSet = sets.find(s => s.name === selectedSet);
      const timeLimitInMinutes = currentSet?.timeLimitMinutes || 0;

      setSelectedSetTimeLimit(timeLimitInMinutes);
      setTimeLeft(timeLimitInMinutes * 60);

      const initialUserAnswers = {};
      questionsRes.data.forEach(q => {
        initialUserAnswers[q._id] = null;
      });
      setUserAnswers(initialUserAnswers);

      setCurrentPhase('examInProgress');
      startTimer();
    } catch (err) {
      console.error('Error starting exam:', err.response ? err.response.data : err);
      setError(`Failed to load exam questions: ${err.response?.data?.message || err.message}`);
    } finally {
      setLoading(false);
    }
  };

  const startTimer = () => {
    clearInterval(timerIntervalRef.current);
    timerIntervalRef.current = setInterval(() => {
      setTimeLeft(prevTime => {
        if (prevTime <= 1) {
          clearInterval(timerIntervalRef.current);
          submitExam(true);
          return 0;
        }
        return prevTime - 1;
      });
    }, 1000);
  };

  const formatTime = (seconds) => {
    const minutes = Math.floor(seconds / 60);
    const remainingSeconds = seconds % 60;
    return `${minutes.toString().padStart(2, '0')}:${remainingSeconds.toString().padStart(2, '0')}`;
  };

  const handleOptionSelect = (questionId, optionLetter) => {
    setUserAnswers(prevAnswers => ({
      ...prevAnswers,
      [questionId]: optionLetter
    }));
  };

  const submitExam = async (timeUp = false) => {
    clearInterval(timerIntervalRef.current);

    setLoading(true);
    setError(null);

    let score = 0;
    let correctAnswersCount = 0;
    const totalQuestions = questions.length;
    const timeTaken = (selectedSetTimeLimit * 60) - timeLeft;

    const answersForSubmission = questions.map(q => {
      const selected = userAnswers[q._id];
      const isCorrect = selected === q.correctAnswer;
      if (isCorrect) {
        score += 1;
        correctAnswersCount += 1;
      }
      return {
        questionId: q._id,
        selectedOption: selected,
        isCorrect: isCorrect
      };
    });

    try {
      const examAttemptData = {
        userId: user._id,
        category: selectedCategory,
        section: selectedSection,
        set: selectedSet,
        examAttemptId: new Date().toISOString(),
        score: score,
        totalQuestions: totalQuestions,
        correctAnswers: correctAnswersCount,
        duration: timeTaken,
        answers: answersForSubmission,
        submittedAt: new Date().toISOString()
      };

      const res = await axios.post('http://localhost:3000/api/user/exam-history', examAttemptData);

      setExamResult({
        score: res.data.examResult.score,
        totalQuestions: res.data.examResult.totalQuestions,
        correctAnswersCount: res.data.examResult.correctAnswers,
        timeTaken: res.data.examResult.duration,
        timeUp: timeUp,
        examAttemptId: res.data.examResult.examId
      });

      setCurrentPhase('examSubmitted');
      alert('✅ Exam submitted successfully!' + (timeUp ? ' Time ran out.' : ''));
    } catch (err) {
      console.error('Error submitting exam:', err.response ? err.response.data : err);
      setError(`Failed to submit exam: ${err.response?.data?.message || err.message}`);
      setCurrentPhase('examSubmitted');
    } finally {
      setLoading(false);
    }
  };

  const viewAnswers = async () => {
    setLoading(true);
    setError(null);
    try {
      if (!user?._id || !examResult?.examAttemptId) {
        setError('Cannot retrieve review data: User ID or Exam Attempt ID missing.');
        setLoading(false);
        return;
      }

      const res = await axios.get(`http://localhost:3000/api/user/exam-history/${user._id}/${examResult.examAttemptId}`);

      setExamDetailsForReview(res.data.reviewData);
      setCurrentPhase('viewAnswers');
    } catch (err) {
      console.error('Error fetching answers for review:', err.response ? err.response.data : err);
      setError(`Failed to load answers for review: ${err.response?.data?.message || err.message}`);
    } finally {
      setLoading(false);
    }
  };

  // --- Render Functions for each phase ---

  const renderCategorySelection = () => (
    <div className="max-w-xl p-6 mx-auto space-y-4 bg-white rounded-lg shadow-md">
      <h2 className="mb-4 text-2xl font-bold text-center text-gray-800">Select Exam Paper</h2>
      {user && (
        <p className="text-sm text-center text-gray-600">
          Welcome, <span className="font-semibold">{user.firstName}</span>! Your subscription status: <strong className={isUserPaid ? 'text-green-600' : 'text-red-600'}>
            {isUserPaid ? 'Paid' : 'Free'}
          </strong>
          {isUserPaid && user.subscriptions && user.subscriptions.length > 0 && 
            ` (${user.subscriptions.find(sub => sub.status === 'active')?.planName || 'Active Plan'})`}
        </p>
      )}
      {error && <p className="text-center text-red-600">{error}</p>}

      {/* Category Selection */}
      <div>
        <label htmlFor="category" className="block mb-1 text-sm font-medium text-gray-700">Category</label>
        <select
          id="category"
          value={selectedCategory}
          onChange={(e) => setSelectedCategory(e.target.value)}
          className="w-full p-2.5 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500 transition duration-150 ease-in-out"
          disabled={loading}
        >
          <option value="">-- Select Category --</option>
          {categories.map(cat => {
            const hasAccessibleSectionInThisCategory = cat.sections.some(sec => 
              isUserPaid || isSectionAccessibleForFreeUser(cat.category, sec.name)
            );
            const isDisabledCategoryOption = !isUserPaid && !hasAccessibleSectionInThisCategory;

            return (
              <option key={cat.category} value={cat.category} disabled={isDisabledCategoryOption}>
                {cat.category} {isDisabledCategoryOption ? ' (Upgrade Required)' : ''}
              </option>
            );
          })}
        </select>
      </div>

      {/* Section Selection */}
      {selectedCategory && (
        <div>
          <label htmlFor="section" className="block mb-1 text-sm font-medium text-gray-700">Section</label>
          <select
            id="section"
            value={selectedSection}
            onChange={(e) => setSelectedSection(e.target.value)}
            className="w-full p-2.5 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
            disabled={loading || sections.length === 0}
          >
            <option value="">-- Select Section --</option>
            {sections.map(sec => {
              const isDisabledSectionOption = !isUserPaid && !isSectionAccessibleForFreeUser(selectedCategory, sec.name);
              return (
                <option key={sec.name} value={sec.name} disabled={isDisabledSectionOption}>
                  {sec.name} {isDisabledSectionOption ? ' (Paid - Upgrade Required)' : ''}
                </option>
              );
            })}
          </select>
        </div>
      )}

      {/* Set Selection */}
      {selectedSection && (
        <div>
          <label htmlFor="set" className="block mb-1 text-sm font-medium text-gray-700">Set</label>
          <select
            id="set"
            value={selectedSet}
            onChange={(e) => {
              setSelectedSet(e.target.value);
              const selectedSetObject = sets.find(s => s.name === e.target.value);
              setSelectedSetTimeLimit(selectedSetObject ? (selectedSetObject.timeLimitMinutes || 0) : 0);
            }}
            className="w-full p-2.5 border border-gray-300 rounded-md focus:ring-blue-500 focus:border-blue-500"
            disabled={loading || sets.length === 0}
          >
            <option value="">-- Select Set --</option>
            {sets.map(set => (
              <option key={set.name} value={set.name}>
                {set.name} {set.timeLimitMinutes ? ` (${set.timeLimitMinutes} min)` : ''}
              </option>
            ))}
          </select>
        </div>
      )}

      <button
        onClick={startExam}
        className="w-full px-4 py-2 font-medium text-white transition duration-150 ease-in-out bg-green-600 rounded-md hover:bg-green-700"
        disabled={loading || !selectedSet}
      >
        {loading ? 'Loading Exam...' : 'Start Exam'}
      </button>
    </div>
  );

  const renderExamInProgress = () => (
    <div className="max-w-3xl p-6 mx-auto bg-white rounded-lg shadow-md">
      <h2 className="mb-4 text-2xl font-bold text-center text-gray-800">
        Exam: {selectedSet} ({selectedCategory} &gt; {selectedSection})
      </h2>
      <div className="mb-4 font-mono text-lg text-right text-gray-700">
        Time Left: <span className="font-bold text-red-600">{formatTime(timeLeft)}</span>
      </div>
      {loading && <p className="text-center text-gray-600">Loading questions...</p>}
      {error && <p className="text-center text-red-600">{error}</p>}

      <div className="space-y-6">
        {questions.map((question, qIndex) => (
          <div key={question._id} className="p-4 border border-gray-200 rounded-md bg-gray-50">
            <p className="mb-2 text-lg font-semibold">Q{qIndex + 1}: {question.questionText}</p>
            {question.questionImage && (
              <img src={`http://localhost:3000/${question.questionImage}`} alt="Question visual" className="h-auto max-w-full mb-2 rounded-md" onError={(e) => { e.target.onerror = null; e.target.src="https://placehold.co/300x200/cccccc/000000?text=Image+Not+Found"; }}/>
            )}
            {question.questionAudio && (
              <audio controls src={`http://localhost:3000/${question.questionAudio}`} className="w-full mb-2">
                Your browser does not support the audio element.
              </audio>
            )}
            <div className="space-y-2">
              {question.options.map((option, oIndex) => (
                <label key={oIndex} className="flex items-center p-2 space-x-2 rounded-md cursor-pointer hover:bg-gray-100">
                  <input
                    type="radio"
                    name={`question-${question._id}`}
                    value={String.fromCharCode(97 + oIndex)}
                    checked={userAnswers[question._id] === String.fromCharCode(97 + oIndex)}
                    onChange={() => handleOptionSelect(question._id, String.fromCharCode(97 + oIndex))}
                    className="w-4 h-4 text-blue-600 form-radio"
                  />
                  <span className="font-bold">{String.fromCharCode(65 + oIndex)}.</span>{' '}
                  {option.type === 'text' && <span>{option.content}</span>}
                  {option.type === 'image' && (
                    <img src={`http://localhost:3000/${option.content}`} alt={`Option ${String.fromCharCode(65 + oIndex)}`} className="inline-block max-w-[80px] max-h-[80px] rounded" onError={(e) => { e.target.onerror = null; e.target.src="https://placehold.co/80x80/cccccc/000000?text=Option+Image"; }}/>
                  )}
                  {option.type === 'audio' && (
                    <audio controls src={`http://localhost:3000/${option.content}`} className="inline-block w-3/4">
                      Your browser does not support the audio element.
                    </audio>
                  )}
                </label>
              ))}
            </div>
          </div>
        ))}
      </div>

      <button
        onClick={() => submitExam(false)} // Pass false as timeUp
        className="w-full px-4 py-3 mt-6 font-medium text-white transition duration-150 ease-in-out bg-indigo-600 rounded-md hover:bg-indigo-700"
        disabled={loading}
      >
        {loading ? 'Submitting...' : 'Submit Exam'}
      </button>
    </div>
  );

  const renderExamSubmitted = () => (
    <div className="max-w-xl p-6 mx-auto space-y-4 text-center bg-white rounded-lg shadow-md">
      <h2 className="mb-4 text-2xl font-bold text-gray-800">Exam Completed!</h2>
      {error && <p className="mb-4 text-red-600">{error}</p>}
      {examResult && (
        <div className="space-y-2 text-gray-700">
          <p className="text-lg">Your Score: <span className="font-bold text-blue-700">{examResult.score} / {examResult.totalQuestions}</span></p>
          <p>Correct Answers: <span className="font-bold text-green-700">{examResult.correctAnswersCount}</span></p>
          <p>Time Taken: <span className="font-bold">{formatTime(examResult.timeTaken)}</span></p>
          {examResult.timeUp && <p className="font-semibold text-red-500">Time ran out!</p>}
        </div>
      )}
      <button
        onClick={viewAnswers}
        className="w-full px-4 py-2 mt-4 font-medium text-white transition duration-150 ease-in-out bg-purple-600 rounded-md hover:bg-purple-700"
        disabled={loading}
      >
        {loading ? 'Loading Review...' : 'View Answers'}
      </button>
      <button
        onClick={() => {
          setCurrentPhase('categorySelection');
          setQuestions([]);
          setUserAnswers({});
          setExamResult(null);
          setExamDetailsForReview(null);
          setError(null);
        }}
        className="w-full px-4 py-2 mt-2 font-medium text-gray-800 transition duration-150 ease-in-out bg-gray-300 rounded-md hover:bg-gray-400"
      >
        Start New Exam
      </button>
    </div>
  );

  const renderViewAnswers = () => (
    <div className="max-w-3xl p-6 mx-auto bg-white rounded-lg shadow-md">
      <h2 className="mb-4 text-2xl font-bold text-center text-gray-800">
        Exam Review: {selectedSet} ({selectedCategory} &gt; {selectedSection})
      </h2>
      {error && <p className="mb-4 text-center text-red-600">{error}</p>}

      {examDetailsForReview && examDetailsForReview.length > 0 ? (
        <div className="space-y-6">
          {examDetailsForReview.map((question, qIndex) => (
            <div key={question._id || qIndex} className="p-4 border border-gray-200 rounded-md bg-gray-50">
              <p className="mb-2 text-lg font-semibold">Q{qIndex + 1}: {question.questionText}</p>
              {question.questionImage && (
                <img src={`http://localhost:3000/${question.questionImage}`} alt="Question visual" className="h-auto max-w-full mb-2 rounded-md" onError={(e) => { e.target.onerror = null; e.target.src="https://placehold.co/300x200/cccccc/000000?text=Image+Not+Found"; }}/>
              )}
              {question.questionAudio && (
                <audio controls src={`http://localhost:3000/${question.questionAudio}`} className="w-full mb-2">
                  Your browser does not support the audio element.
                </audio>
              )}
              <ul className="pl-5 space-y-1 list-disc">
                {question.options.map((option, oIndex) => (
                  <li
                    key={oIndex}
                    className={`
                      ${String.fromCharCode(97 + oIndex) === question.correctAnswer ? 'text-green-700 font-medium' : 'text-gray-800'}
                      ${String.fromCharCode(97 + oIndex) === question.userSelectedOption && String.fromCharCode(97 + oIndex) !== question.correctAnswer ? 'text-red-700 font-bold' : ''}
                    `}
                  >
                    <span className="font-bold">{String.fromCharCode(65 + oIndex)}.</span>{' '}
                    {option.type === 'text' && <span>{option.content}</span>}
                    {option.type === 'image' && (
                      <img src={`http://localhost:3000/${option.content}`} alt={`Option ${String.fromCharCode(65 + oIndex)}`} className="inline-block max-w-[100px] max-h-[100px] rounded" onError={(e) => { e.target.onerror = null; e.target.src="https://placehold.co/100x100/cccccc/000000?text=Option+Image"; }}/>
                    )}
                    {option.type === 'audio' && (
                      <audio controls src={`http://localhost:3000/${option.content}`} className="inline-block w-3/4">
                        Your browser does not support the audio element.
                      </audio>
                    )}
                    {String.fromCharCode(97 + oIndex) === question.correctAnswer && <span className="ml-2 text-xs">(Correct Answer)</span>}
                    {String.fromCharCode(97 + oIndex) === question.userSelectedOption && question.userSelectedOption !== question.correctAnswer && <span className="ml-2 text-xs font-bold text-red-700">(Your Answer)</span>}
                    {String.fromCharCode(97 + oIndex) === question.userSelectedOption && question.userSelectedOption === question.correctAnswer && <span className="ml-2 text-xs font-bold text-green-700">(Your Answer)</span>}
                  </li>
                ))}
              </ul>
              {question.userSelectedOption === null && <p className="mt-2 text-sm text-yellow-600">You did not answer this question.</p>}
            </div>
          ))}
        </div>
      ) : (
        <p className="text-center text-gray-600">No review data available.</p>
      )}

      <button
        onClick={() => {
          setCurrentPhase('categorySelection');
          setQuestions([]);
          setUserAnswers({});
          setExamResult(null);
          setExamDetailsForReview(null);
          setError(null);
        }}
        className="w-full px-4 py-2 mt-6 font-medium text-gray-800 transition duration-150 ease-in-out bg-gray-300 rounded-md hover:bg-gray-400"
      >
        Back to Exam Summary
      </button>
      <button
        onClick={() => {
          setCurrentPhase('categorySelection');
          setQuestions([]);
          setUserAnswers({});
          setExamResult(null);
          setExamDetailsForReview(null);
          setError(null);
        }}
        className="w-full px-4 py-2 mt-2 font-medium text-white transition duration-150 ease-in-out bg-blue-600 rounded-md hover:bg-blue-700"
      >
        Start New Exam
      </button>
    </div>
  );

  // Main render based on current phase
  return (
    <div className="min-h-screen p-8 bg-gray-100">
      {currentPhase === 'categorySelection' && renderCategorySelection()}
      {currentPhase === 'examInProgress' && renderExamInProgress()}
      {currentPhase === 'examSubmitted' && renderExamSubmitted()}
      {currentPhase === 'viewAnswers' && renderViewAnswers()}
    </div>
  );
}
